                    <Loader2 size={11} className={`animate-spin ${isVersa ? 'text-amber-500' : 'text-portal'}`} />
                    <span>Aether Stream Active</span>
                  </div>
                  {estimatedSecondsRemaining !== null && (
                    <span>~{estimatedSecondsRemaining}s left</span>
                  )}
