            <motion.div
              animate={{ rotate: 360 }}
              transition={{ repeat: Infinity, duration: 10, ease: "linear" }}
              className={`absolute -inset-1 rounded-full border border-dashed ${isVersa ? 'border-amber-500/25' : 'border-portal/25'}`}
            />

            {/* Glowing Ambient Radial BG */}
