                                 tabIndex={0} onKeyDown={(e) => { if (e.key === "Enter" || e.key === " ") { e.preventDefault(); e.currentTarget.click(); } }} onClick={() => {
                                  if (existingBookmark) {
                                    handleRemoveBookmark(
                                      selectedChapter.number,
                                      index,
                                    );
                                  } else {
                                    setEditingBookmarkParagraphIndex(index);
                                    setBookmarkNoteText(
                                      existingBookmark
                                        ? existingBookmark.note || ""
