                    : (selectedChapter.generatedContent || "")
                        .split("\n\n")
                        .map((paragraph, index) => {
                          if (!paragraph.trim()) return null;
                          const { cleanText, sfxList } =
                            extractSFXCues(paragraph);
                          if (!cleanText) return null;
                          const isSystemLine =
                            cleanText.startsWith("[") &&
                            cleanText.endsWith("]");
                          if (isSystemLine) {
                            return (
                              <SystemBlock
                                key={index}
                                id={`para-${index}`}
                                data-block-index={index}
                                content={cleanText}
