import { describe, it, expect, vi } from 'vitest';
import { extractJsonBlocks, extractJsonMeta, runMemoryLinter } from './storyEngineHelpers';
import { secureStorage } from '../lib/encryption';

describe('storyEngineHelpers', () => {
  describe('extractJsonBlocks', () => {
    it('extracts JSON array from text', () => {
      const raw = `Some text before
[
  { "text": "block 1" },
  { "text": "block 2" }
]
Some text after`;
      const result = extractJsonBlocks(raw);
      expect(result).toHaveLength(2);
      expect(result[0].text).toBe('block 1');
      expect(result[1].text).toBe('block 2');
    });

    it('extracts individual JSON objects from lines', () => {
      const raw = `
{ "text": "block 1" }
some random text
{ "content": "block 2" }
`;
      const result = extractJsonBlocks(raw);
      expect(result).toHaveLength(2);
      expect(result[0].text).toBe('block 1');
      expect(result[1].text).toBe('block 2');
    });

    it('extracts nested JSON objects safely', () => {
      const raw = `Here is some content: {"text": "hello { world }", "type": "paragraph"}`;
      const result = extractJsonBlocks(raw);
      expect(result).toHaveLength(1);
      expect(result[0].text).toBe('hello { world }');
    });

    it('returns empty array if no valid JSON found', () => {
      const result = extractJsonBlocks("Just some random text without JSON");
      expect(result).toHaveLength(0);
    });
  });

  describe('extractJsonMeta', () => {
    it('extracts clean JSON from markdown', () => {
      const raw = `
\`\`\`json
{ "title": "New Chapter", "status": "draft" }
\`\`\`
`;
      const result = extractJsonMeta(raw);
      expect(result).toEqual({ title: "New Chapter", status: "draft" });
    });

    it('removes <think> tags before parsing', () => {
      const raw = `
<think>Thinking process</think>
{ "title": "Clean Title" }
`;
      const result = extractJsonMeta(raw);
      expect(result.title).toBe("Clean Title");
    });

    it('finds the longest object if multiple exist or messy formatting', () => {
      const raw = `
Here is something: {"small": 1}
And the main meta: {"title": "Main Title", "summary": "Big summary of the chapter that makes it longer"}
`;
      const result = extractJsonMeta(raw);
      expect(result.title).toBe("Main Title");
    });

    it('returns empty object if no JSON found', () => {
      const result = extractJsonMeta("No JSON here");
      expect(result).toEqual({});
    });
  });

  describe('runMemoryLinter', () => {
    it('warns if deceased character is mentioned in text', () => {
      const prevMemory = {
        characters: [{ name: 'Bob', status: 'deceased' }]
      } as any;
      const warnings = runMemoryLinter(prevMemory, {} as any, 'Bob walked into the room.');
      expect(warnings).toHaveLength(1);
      expect(warnings[0]).toContain('Deceased character "Bob" was referenced');
    });

    it('warns about similar character names', () => {
      const nextMemory = {
        characters: [{ name: 'Alexander' }, { name: 'Alexandur' }]
      } as any;
      const warnings = runMemoryLinter({} as any, nextMemory, '');
      expect(warnings).toHaveLength(1);
      expect(warnings[0]).toContain('Potential duplicate character names');
    });

    it('ignores same family names for similarity warning', () => {
      const nextMemory = {
        characters: [{ name: 'Smith John' }, { name: 'Smith Jane' }]
      } as any;
      const warnings = runMemoryLinter({} as any, nextMemory, '');
      expect(warnings).toHaveLength(0);
    });

    it('warns if plot thread is marked unresolved after being resolved', () => {
      const prevMemory = {
        resolvedPlotThreads: ['Find the sword']
      } as any;
      const nextMemory = {
        unresolvedPlotThreads: ['Find the sword']
      } as any;
      const warnings = runMemoryLinter(prevMemory, nextMemory, '');
      expect(warnings).toHaveLength(1);
      expect(warnings[0]).toContain('previously resolved but is now marked unresolved');
    });
  });
});

import { useEffect, useRef, useCallback } from 'react';
import { useAppStore } from '../store/useAppStore';

/**
 * useCinematicScroll
 *
 * Flawless, cinematic "requestAnimationFrame" engine for infinite auto-scrolling.
 * Reads global scroll state and physically increments scrollTop using a sub-pixel
 * accumulator for maximum frame-by-frame smoothness.
 */
export function useCinematicScroll(containerRef: React.RefObject<HTMLElement>, isActive: boolean) {
  const isAutoScrolling = isActive;
  const scrollSpeed = useAppStore(state => state.scrollSpeed);

  const requestRef = useRef<number | undefined>(undefined);
  const lastTimeRef = useRef<number | undefined>(undefined);
  const scrollAccumulatorRef = useRef<number>(0);
  const isYieldingRef = useRef<boolean>(false);
  const yieldTimeoutRef = useRef<NodeJS.Timeout | undefined>(undefined);

  const isActiveRef = useRef(isActive);
  useEffect(() => {
    isActiveRef.current = isActive;
  }, [isActive]);

  const animateRef = useRef<(time: number) => void>(() => {});

  useEffect(() => {
    animateRef.current = (time: number) => {
      // If user is actively yielding, or auto-scroll is disabled, stop animating
      if (isYieldingRef.current || !isAutoScrolling) {
        lastTimeRef.current = undefined;
        return;
      }

      if (lastTimeRef.current != null && containerRef.current) {
        const deltaTime = time - lastTimeRef.current;

        // Calculate how many pixels we should scroll based on time elapsed
        // v = d/t => d = v * t
        // scrollSpeed is pixels per second, so we divide by 1000 for milliseconds
        const scrollAmount = (scrollSpeed * deltaTime) / 1000;

        // Accumulate fractional sub-pixels to avoid integer-rounding stutter
        scrollAccumulatorRef.current += scrollAmount;

        // When our accumulator hits at least 1 pixel, physically scroll the container
        if (scrollAccumulatorRef.current >= 1) {
          const pixelsToScroll = Math.floor(scrollAccumulatorRef.current);

          // Prevent scrolling past the maximum bottom
          const maxScroll = containerRef.current.scrollHeight - containerRef.current.clientHeight;
          if (containerRef.current.scrollTop < maxScroll) {
              containerRef.current.scrollTop += pixelsToScroll;
          }

          // Subtract only the whole pixels we applied, keeping the decimal fraction
          scrollAccumulatorRef.current -= pixelsToScroll;
        }
      }

      lastTimeRef.current = time;
      requestRef.current = requestAnimationFrame(animateRef.current);
    };
  }, [isAutoScrolling, scrollSpeed, containerRef]);

  // Main lifecycle for the rAF loop
  useEffect(() => {
    if (isAutoScrolling && !isYieldingRef.current) {
      lastTimeRef.current = undefined;
      requestRef.current = requestAnimationFrame(animateRef.current);
    }

    return () => {
      if (requestRef.current) {
        cancelAnimationFrame(requestRef.current);
      }
    };
  }, [isAutoScrolling]);

  // User Yield Logic: instantly pause the rAF loop upon user interaction,
  // and set a 2000ms debounce before resuming.
  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;

    const handleUserInteraction = () => {
      if (!isActiveRef.current) return;

      isYieldingRef.current = true;

      // Stop the current animation frame immediately to yield to user
      if (requestRef.current) {
        cancelAnimationFrame(requestRef.current);
        lastTimeRef.current = undefined; 
      }

      if (yieldTimeoutRef.current) {
        clearTimeout(yieldTimeoutRef.current);
      }

      // Resume engine after 2000ms of no interactions
      yieldTimeoutRef.current = setTimeout(() => {
        isYieldingRef.current = false;

        // If the global state still wants us to scroll, restart the loop
        if (isActiveRef.current) {
          lastTimeRef.current = undefined;
          requestRef.current = requestAnimationFrame(animateRef.current);
        }
      }, 2000);
    };

    // Add passive listeners for smooth scrolling interactions
    container.addEventListener('wheel', handleUserInteraction, { passive: true });
    container.addEventListener('touchstart', handleUserInteraction, { passive: true });
    container.addEventListener('touchmove', handleUserInteraction, { passive: true });

    return () => {
      container.removeEventListener('wheel', handleUserInteraction);
      container.removeEventListener('touchstart', handleUserInteraction);
      container.removeEventListener('touchmove', handleUserInteraction);
      if (yieldTimeoutRef.current) {
        clearTimeout(yieldTimeoutRef.current);
      }
    };
  }, [containerRef]);
}

