    // Fallback 1: ylacombe/kokoro-82m Gradio Space
    if (!base64Audio) {
      console.log(`[TTS] Falling back to public Hugging Face Space (ylacombe/kokoro-82m) for voice '${speakerVoice}'...`);
      try {
