            data: [
              text,
              speakerVoice,
              1.0, // speed
              lang
            ]
          })
        });

        if (hfResponse.ok) {
          const hfJson: any = await hfResponse.json();
          if (hfJson && hfJson.data && hfJson.data[0]) {
